// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		// Per ddx-95ec5ed5 AC §3 the axon backend ships behind a feature
		// flag until ddx-743bc194 (chaos conformance) signs off. Routing
		// only happens when DDX_AXON_EXPERIMENTAL is truthy; otherwise we
		// warn once and fall through to JSONL so the workspace stays
		// usable on misconfiguration.
		if AxonExperimentalEnabled() {
			s.backend = NewAxonBackend(s.Dir, s.LockWait)
		} else {
			fmt.Fprintf(os.Stderr, "bead: backend=axon ignored: set %s=1 to opt in (axon backend is experimental)\n", AxonExperimentalEnv)
		}
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init() error {
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID() (string, error) {
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("bead: gen id: %w", err)
	}
	return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll() ([]Bead, error) {
	return s.ReadAllFiltered(nil)
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	if pred == nil {
		return beads, nil
	}
	out := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if pred(b) {
			out = append(out, b)
		}
	}
	return out, nil
}

func (s *Store) readAllRaw() ([]Bead, []string, error) {
	data, err := os.ReadFile(s.File)
	if os.IsNotExist(err) {
		return nil, nil, nil
	}
	if err != nil {
		return nil, nil, fmt.Errorf("read: %w", err)
	}
	beads, warnings, err := parseBeadJSONL(data)
	if err != nil {
		return nil, nil, err
	}
	return beads, warnings, nil
}

func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
	scanner := bufio.NewScanner(bytes.NewReader(data))
	// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
	// reviewer stream dumped into events[].body, and bd-exported lines stacking
	// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
	// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)

	var beads []Bead
	var warnings []string
	lineNo := 0
	for scanner.Scan() {
		lineNo++

package bead

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

// BackendAxon selects the axon-backed RawBackend. Per TD-030 D3 the on-disk
// shape splits beads from their events: one row per bead in the
// ddx_beads collection, plus one entity per event in the
// ddx_bead_events collection linked back to its bead via event_of.
//
// The implementation in axon_backend.go is an in-process emulation of the
// axon GraphQL surface. It serializes the two collections to JSONL files
// under <dir>/axon/ and acquires a single directory lock around mutations.
// The wire-protocol path (genqlient against a real axon server, per TD-030
// §"Wire transport") is the GA delivery; this RawBackend keeps the same
// two-collection split and OCC-compatible bead row schema so the wire path
// is a contained refactor.
//
// AC §3 ("Behind a feature flag until ddx-3ec0chaos signs off"): NewStore
// only routes to AxonBackend when the operator opts in via
// DDX_AXON_EXPERIMENTAL=1. With the flag unset, beads.backend=axon falls
// through to the JSONL default and a stderr warning is emitted so the
// misconfiguration is visible without breaking the workspace.
const BackendAxon = "axon"

// AxonExperimentalEnv gates whether the axon backend may be selected. The
// flag is intentionally separate from beads.backend so the chaos-test bead
// (ddx-743bc194) can flip operators to axon machine-by-machine without
// editing every project's config.
const AxonExperimentalEnv = "DDX_AXON_EXPERIMENTAL"

// axonSchemaVersion is written into every persisted entity. Schema upgrades
// are handled lazy-on-read until axon FEAT-017 ships native schema
// migration (per TD-030 v1 policy on schema versioning).
const axonSchemaVersion = 1

// AxonDirName is the per-store axon subdirectory under .ddx that holds the
// two-collection snapshot files and the lock dir.
const AxonDirName = "axon"

// AxonBeadsCollection / AxonEventsCollection are the logical collection names
// from TD-030's schema mapping. They are surfaced as the on-disk filenames so
// inspecting the directory tells the operator which collection an entity
// belongs to.
const (
	AxonBeadsCollection  = "ddx_beads"
	AxonEventsCollection = "ddx_bead_events"
)

// AxonBackend stores the bead corpus in axon's two-collection shape.
//
// On WriteAll the backend splits each bead's inline Extra["events"] into one
// entity per event under ddx_bead_events and persists the bead row (sans
// inline events) under ddx_beads. ReadAll re-merges events back into
// Extra["events"] so the higher-level Store and the chaos suite see the
// uniform inline-events shape they expect.
//
// Beads with Extra[events_attachment] set (post-Close externalisation) are
// persisted with their events array empty in axon's events collection. The
// attachment file remains the canonical source for those events so Store's
// existing read path (eventsForBead) keeps working unchanged.
type AxonBackend struct {
	Dir        string
	BeadsFile  string
	EventsFile string
	LockDir    string
	LockWait   time.Duration
}

// Compile-time check: AxonBackend satisfies RawBackend.
var _ RawBackend = (*AxonBackend)(nil)

// NewAxonBackend constructs an axon-backed RawBackend rooted at dir. dir is
// the .ddx directory for the project; collection files and the lock live
// under <dir>/axon/.
func NewAxonBackend(dir string, lockWait time.Duration) *AxonBackend {
	root := filepath.Join(dir, AxonDirName)
	return &AxonBackend{
		Dir:        root,
		BeadsFile:  filepath.Join(root, AxonBeadsCollection+".jsonl"),
		EventsFile: filepath.Join(root, AxonEventsCollection+".jsonl"),
		LockDir:    filepath.Join(root, ".lock"),
		LockWait:   lockWait,
	}
}

// AxonExperimentalEnabled reports whether the operator has opted in to the
// experimental axon backend via DDX_AXON_EXPERIMENTAL=1. NewStore consults
// this before routing beads.backend=axon to AxonBackend.
func AxonExperimentalEnabled() bool {
	switch strings.ToLower(strings.TrimSpace(os.Getenv(AxonExperimentalEnv))) {
	case "1", "true", "yes", "on":
		return true
	}
	return false
}

func (a *AxonBackend) Init() error {
	if err := os.MkdirAll(a.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: axon init dir: %w", err)
	}
	for _, path := range []string{a.BeadsFile, a.EventsFile} {
		f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY, 0o644)
		if err != nil {
			return fmt.Errorf("bead: axon init %s: %w", path, err)
		}
		if err := f.Close(); err != nil {
			return fmt.Errorf("bead: axon close %s: %w", path, err)
		}
	}
	return nil
}

// ReadAll loads bead rows and event entities from disk and re-merges events
// back into each bead's Extra["events"]. Orphan events (event_of pointing at
// a missing bead, e.g. after a partial-write crash) are silently dropped.
func (a *AxonBackend) ReadAll() ([]Bead, error) {
	beads, err := a.readBeadRows()
	if err != nil {
		return nil, err
	}
	events, err := a.readEventEntities()
	if err != nil {
		return nil, err
	}
	// Index beads by id so we can attach events and drop orphans.
	byID := make(map[string]*Bead, len(beads))
	for i := range beads {
		byID[beads[i].ID] = &beads[i]
	}
	// Group events by bead id with exact per-bead capacity so the read path
	// does not repeatedly grow slices while rebuilding the inline shape.
	counts := make(map[string]int, len(events))
	for _, ev := range events {
		if _, ok := byID[ev.beadID]; !ok {
			continue // orphan
		}
		counts[ev.beadID]++
	}
	grouped := make(map[string][]BeadEvent, len(counts))
	for id, count := range counts {
		grouped[id] = make([]BeadEvent, 0, count)
	}
	for _, ev := range events {
		if _, ok := byID[ev.beadID]; !ok {
			continue
		}
		grouped[ev.beadID] = append(grouped[ev.beadID], ev.event)
	}
	for id, evs := range grouped {
		b := byID[id]
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		// Skip beads whose events have been externalised — the attachment file
		// is the canonical source post-close and inlining stale events would
		// duplicate the history.
		if hasEventsAttachment(b) {
			continue
		}
		b.Extra["events"] = encodeEventsForExtra(evs)
	}
	return beads, nil
}

// WriteAll splits inline events from each bead and persists both collections.
// Writes are serialised at the directory-lock layer (WithLock); this method
// rewrites both files in temp+rename style so a crash mid-write leaves the
// previous snapshot intact rather than producing torn rows.
func (a *AxonBackend) WriteAll(beads []Bead) error {
	if err := os.MkdirAll(a.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: axon mkdir: %w", err)
	}
	sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })

	var beadsBuf, eventsBuf bytes.Buffer
	for _, b := range beads {
		// Extract and strip inline events for the split.
		var events []BeadEvent
		if b.Extra != nil {
			if raw, ok := b.Extra["events"]; ok {
				events = decodeBeadEvents(raw)
			}
		}
		stripped := beadWithoutInlineEvents(b)
		row, err := axonEncodeBead(stripped)
		if err != nil {
			return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
		}
		beadsBuf.Write(row)
		beadsBuf.WriteByte('\n')

		for i, ev := range events {
			data, err := axonEncodeEvent(b.ID, i, ev)
			if err != nil {
				return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
			}
			eventsBuf.Write(data)
			eventsBuf.WriteByte('\n')
		}
	}

	// Write events first so a crash between the two writes leaves orphan
	// events (which ReadAll silently drops) rather than a bead row whose
	// events have not landed yet — favouring the safer side of the partial-
	// write window for an audit log.
	if err := writeAtomicFile(a.EventsFile, eventsBuf.Bytes()); err != nil {
		return fmt.Errorf("bead: axon write events: %w", err)
	}
	if err := writeAtomicFile(a.BeadsFile, beadsBuf.Bytes()); err != nil {
		return fmt.Errorf("bead: axon write beads: %w", err)
	}
	return nil
}

func (a *AxonBackend) WithLock(fn func() error) error {
	wait := a.LockWait
	if wait <= 0 {
		wait = 10 * time.Second
	}
	if err := acquireDirLock(a.Dir, a.LockDir, wait); err != nil {
		return err
	}
	defer os.RemoveAll(a.LockDir)
	return fn()
}

// beadWithoutInlineEvents returns a shallow copy of b whose Extra map omits
// the "events" key. The original Extra map is not mutated so callers can
// continue using the in-memory bead value after the split.
func beadWithoutInlineEvents(b Bead) Bead {
	if b.Extra == nil {
		return b
	}
	if _, ok := b.Extra["events"]; !ok {
		return b
	}
	cp := make(map[string]any, len(b.Extra))
	for k, v := range b.Extra {
		if k == "events" {
			continue
		}
		cp[k] = v
	}
	b.Extra = cp
	return b
}

// axonEncodeBead writes a bead in axon's row shape:
//
//	{ "_collection": "ddx_beads", "schema_version": 1, "data": {<bead JSON>} }

---
//	{ "_collection": "ddx_beads", "schema_version": 1, "data": {<bead JSON>} }
//
// The wrapper carries the collection name and schema version that a future
// genqlient-driven implementation needs; the data field is the same bead
// JSON the JSONL backend writes, so import/export round-trip continues to
// share marshalBead.
func axonEncodeBead(b Bead) ([]byte, error) {
	envelope := axonEntityEnvelope{
		Collection:    AxonBeadsCollection,
		SchemaVersion: axonSchemaVersion,
		Data:          axonBeadData{Bead: b},
	}
	return json.Marshal(envelope)
}

// axonEncodeEvent writes one event entity in the ddx_bead_events
// collection. The event_of field is the link target back to the parent bead
// (per TD-030 D3); index gives a deterministic position so re-reads preserve
// insertion order even when on-disk shuffling occurs.
func axonEncodeEvent(beadID string, index int, ev BeadEvent) ([]byte, error) {
	row := axonEventEnvelope{
		Collection:    AxonEventsCollection,
		SchemaVersion: axonSchemaVersion,
		EventOf:       beadID,
		Index:         index,
		Event:         ev,
	}
	return json.Marshal(row)
}

type axonEntityEnvelope struct {
	Collection    string       `json:"_collection"`
	SchemaVersion int          `json:"schema_version"`
	Data          axonBeadData `json:"data"`
}

type axonBeadData struct {
	Bead
}

func (d axonBeadData) MarshalJSON() ([]byte, error) {
	return marshalBead(d.Bead)
}

func (d *axonBeadData) UnmarshalJSON(data []byte) error {
	b, err := unmarshalBead(data)
	if err != nil {
		return err
	}
	d.Bead = b
	return nil
}

type axonEventEnvelope struct {
	Collection    string    `json:"_collection"`
	SchemaVersion int       `json:"schema_version"`
	EventOf       string    `json:"event_of"`
	Index         int       `json:"index"`
	Event         BeadEvent `json:"event"`
}

func (a *AxonBackend) readBeadRows() ([]Bead, error) {
	data, err := os.ReadFile(a.BeadsFile)
	if os.IsNotExist(err) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("bead: axon read %s: %w", a.BeadsFile, err)
	}
	scanner := bufio.NewScanner(bytes.NewReader(data))
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
	out := make([]Bead, 0, bytes.Count(data, []byte{'\n'}))
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var env axonEntityEnvelope
		if err := json.Unmarshal(line, &env); err != nil {
			return nil, fmt.Errorf("bead: axon parse bead row: %w", err)
		}
		if env.Collection != AxonBeadsCollection || env.Data.ID == "" {
			continue
		}
		out = append(out, env.Data.Bead)
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("bead: axon scan beads: %w", err)
	}
	return foldLatestBeads(out), nil
}

type axonEventRecord struct {
	beadID string
	index  int
	event  BeadEvent
}

func (a *AxonBackend) readEventEntities() ([]axonEventRecord, error) {
	data, err := os.ReadFile(a.EventsFile)
	if os.IsNotExist(err) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("bead: axon read %s: %w", a.EventsFile, err)
	}
	scanner := bufio.NewScanner(bytes.NewReader(data))
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
	out := make([]axonEventRecord, 0, bytes.Count(data, []byte{'\n'}))
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var env axonEventEnvelope
		if err := json.Unmarshal(line, &env); err != nil {
			return nil, fmt.Errorf("bead: axon parse event row: %w", err)
		}
		if env.Collection != AxonEventsCollection || env.EventOf == "" {
			continue
		}
		out = append(out, axonEventRecord{
			beadID: env.EventOf,
			index:  env.Index,
			event:  env.Event,
		})
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("bead: axon scan events: %w", err)
	}
	// Stable sort within each bead so insertion order is recoverable on read
	// regardless of how WriteAll batched lines into the file.
	sort.SliceStable(out, func(i, j int) bool {
		if out[i].beadID != out[j].beadID {
			return out[i].beadID < out[j].beadID
		}
		return out[i].index < out[j].index
	})
	return out, nil
}

package bead

import (
	"fmt"
	"time"
)

// MigrateStats reports what Migrate did in a single pass.
type MigrateStats struct {
	// EventsExternalized is the number of beads whose inline events were
	// moved to the .ddx/attachments/<id>/events.jsonl sidecar.
	EventsExternalized int
	// Archived is the number of closed beads moved from the active
	// collection to beads-archive.
	Archived int
}

// Changed reports whether Migrate mutated on-disk state in this pass.
func (m MigrateStats) Changed() bool {
	return m.EventsExternalized > 0 || m.Archived > 0
}

// Migrate splits the existing active beads collection into the modern
// layout: closed beads' inline events are externalized to the attachment
// store (per ADR-004), and eligible closed beads are moved to the
// beads-archive partner (per TD-027). It is idempotent — a second call
// with no further changes is a no-op.
//
// Migrate uses a permissive archival policy (MinAge=0, MinActiveCount=0)
// so it drains the historical backlog. Routine archival (after Close)
// continues to use DefaultArchivePolicy.
func (s *Store) Migrate() (MigrateStats, error) {
	return s.ArchiveWithEvents(migratePolicy())
}

// MigrateDryRun reports what Migrate would do without mutating disk. It uses
// the same eligibility logic as Migrate (Statuses=[closed], no MinAge floor,
// preserve_dependencies retention).
func (s *Store) MigrateDryRun() (MigrateStats, error) {
	var stats MigrateStats
	if s.Collection != DefaultCollection {
		return stats, fmt.Errorf("bead: migrate dry-run only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
	}
	policy := migratePolicy()

	var beads []Bead
	err := s.WithLock(func() error {
		all, _, rerr := s.readAllLatestRaw()
		if rerr != nil {
			return rerr
		}
		beads = all
		return nil
	})
	if err != nil {
		return stats, err
	}

	referenced := make(map[string]bool)
	for _, b := range beads {
		if b.Status == StatusClosed {
			continue
		}
		for _, dep := range b.DepIDs() {
			referenced[dep] = true
		}
	}

	for _, b := range beads {
		if !containsString(policy.Statuses, b.Status) {
			continue
		}
		if hasInlineEvents(&b) {
			stats.EventsExternalized++
		}
		if referenced[b.ID] {
			continue
		}
		ts := b.UpdatedAt
		if raw, ok := b.Extra["closed_at"].(string); ok {
			if parsed, perr := time.Parse(time.RFC3339, raw); perr == nil {
				ts = parsed
			}
		}
		if policy.MinAge > 0 && time.Now().UTC().Sub(ts) < policy.MinAge {
			continue
		}
		stats.Archived++
	}
	return stats, nil
}

func migratePolicy() ArchivePolicy {
	return ArchivePolicy{
		Statuses:       []string{StatusClosed},
		MinAge:         0,
		MinActiveCount: 0,
		BatchSize:      0,
	}
}

// ArchiveWithEvents externalizes inline events for every bead whose status
// matches policy.Statuses, then archives eligible beads under the same
// policy. This is the operator-facing path used by `ddx bead archive` and
// the internal path used by `ddx bead migrate`.
func (s *Store) ArchiveWithEvents(policy ArchivePolicy) (MigrateStats, error) {
	var stats MigrateStats
	if s.Collection != DefaultCollection {
		return stats, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
	}

	// Step 1: externalize inline events on every eligible-status bead under
	// the active store's lock. This shrinks the row size before we try to
	// archive, so the archive partner inherits already-thin rows.
	err := s.WithLock(func() error {
		beads, _, rerr := s.readAllLatestRaw()
		if rerr != nil {
			return rerr
		}
		dirty := false
		for i := range beads {
			if !containsString(policy.Statuses, beads[i].Status) {
				continue
			}
			if !hasInlineEvents(&beads[i]) {
				continue
			}
			if eerr := s.externalizeEventsInPlace(&beads[i]); eerr != nil {
				return eerr
			}
			stats.EventsExternalized++
			dirty = true
		}
		if !dirty {
			return nil
		}
		return s.WriteAll(beads)
	})
	if err != nil {
		return stats, fmt.Errorf("bead: archive externalize: %w", err)
	}

	moved, err := s.Archive(policy)
	if err != nil {
		return stats, fmt.Errorf("bead: archive: %w", err)
	}
	stats.Archived = len(moved)
	return stats, nil
}

// MigrateAxonStats reports what MigrateToAxon copied in a single pass.
type MigrateAxonStats struct {
	// BeadsMigrated is the total number of distinct bead IDs written into
	// the axon backend (active + archive, deduped on ID).
	BeadsMigrated int
	// EventsMigrated is the total number of inline events written into the
	// ddx_bead_events collection. Externalized events (referenced via
	// Extra[events_attachment]) are not counted because they are not
	// rewritten by the migration — the attachment file remains canonical.
	EventsMigrated int
}

// MigrateToAxon reads beads from the JSONL active collection
// (.ddx/beads.jsonl) and the JSONL archive partner
// (.ddx/beads-archive.jsonl) rooted under s.Dir and writes them losslessly
// into the axon backend (.ddx/axon/). Source files are not modified.
//
// Reads always go through fresh JSONL backends regardless of s.backend so
// the migration is deterministic and not affected by the operator's
// configured backend (e.g. an axon-misconfigured store still migrates from
// the on-disk JSONL files). Active wins on duplicate IDs.
//
// Idempotent: AxonBackend.WriteAll overwrites both collection files in
// temp+rename style, so re-running on the same source state produces an
// identical axon snapshot with no duplicates.
func (s *Store) MigrateToAxon() (MigrateAxonStats, error) {
	var stats MigrateAxonStats

	activeSpec := DefaultRegistry().Resolve(DefaultCollection)
	activeFile, activeLock := activeSpec.PathsUnder(s.Dir)
	activeBackend := NewJSONLBackend(s.Dir, activeFile, activeLock, s.LockWait)

	archiveSpec := DefaultRegistry().Resolve(BeadsArchiveCollection)
	archiveFile, archiveLock := archiveSpec.PathsUnder(s.Dir)
	archiveBackend := NewJSONLBackend(s.Dir, archiveFile, archiveLock, s.LockWait)

	activeBeads, err := activeBackend.ReadAll()
	if err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon read active: %w", err)
	}
	archiveBeads, err := archiveBackend.ReadAll()
	if err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon read archive: %w", err)
	}

	seen := make(map[string]bool, len(activeBeads))
	merged := make([]Bead, 0, len(activeBeads)+len(archiveBeads))
	for _, b := range activeBeads {
		seen[b.ID] = true
		merged = append(merged, b)
	}
	for _, b := range archiveBeads {
		if seen[b.ID] {
			continue
		}
		seen[b.ID] = true
		merged = append(merged, b)
	}

	for i := range merged {
		stats.BeadsMigrated++
		if hasInlineEvents(&merged[i]) {
			stats.EventsMigrated += len(decodeBeadEvents(merged[i].Extra["events"]))
		}
	}

	axon := NewAxonBackend(s.Dir, s.LockWait)
	if err := axon.Init(); err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon init: %w", err)
	}
	if err := axon.WithLock(func() error {
		return axon.WriteAll(merged)
	}); err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon write: %w", err)
	}
	return stats, nil
}

// hasInlineEvents reports whether a bead carries any inline events that
// can still be externalized. An empty array counts as "no inline events"
// so a second migrate pass on an already-externalized bead is a no-op.
func hasInlineEvents(b *Bead) bool {
	if b == nil || b.Extra == nil {
		return false
	}
	raw, ok := b.Extra["events"]
	if !ok {
		return false
	}
	return len(decodeBeadEvents(raw)) > 0
}

